import { describe, it, expect, vi, beforeEach } from 'vitest'
import { getAuthUser, verifyProjectOwnership, verifyCardOwnership, verifyWorkspaceOwnership, handleAuthError } from '@/lib/auth-helpers'
import { prisma } from '@/lib/prisma'
import { createClient } from '@/lib/supabase/server'

// Mock modules
vi.mock('@/lib/supabase/server', () => ({
    createClient: vi.fn()
}))

vi.mock('@/lib/prisma', () => ({
    prisma: {
        projects: {
            findUnique: vi.fn()
        },
        cards: {
            findUnique: vi.fn()
        },
        workspaces: {
            findUnique: vi.fn()
        }
    }
}))

describe('Auth Helpers', () => {
    beforeEach(() => {
        vi.clearAllMocks()
    })

    describe('getAuthUser', () => {
        it('should return user when authenticated', async () => {
            const mockUser = { id: 'user-123', email: 'test@example.com' }
            const mockSupabase = {
                auth: {
                    getUser: vi.fn().mockResolvedValue({
                        data: { user: mockUser },
                        error: null
                    })
                }
            }
            vi.mocked(createClient).mockResolvedValue(mockSupabase as any)

            const user = await getAuthUser()

            expect(user).toEqual(mockUser)
            expect(mockSupabase.auth.getUser).toHaveBeenCalled()
        })

        it('should throw error when not authenticated', async () => {
            const mockSupabase = {
                auth: {
                    getUser: vi.fn().mockResolvedValue({
                        data: { user: null },
                        error: { message: 'Not authenticated' }
                    })
                }
            }
            vi.mocked(createClient).mockResolvedValue(mockSupabase as any)

            await expect(getAuthUser()).rejects.toThrow('Unauthorized')
        })
    })

    describe('verifyProjectOwnership', () => {
        it('should return project when user is owner', async () => {
            const mockProject = {
                id: 'project-123',
                user_id: 'user-123',
                name: 'Test Project'
            }
            vi.mocked(prisma.projects.findUnique).mockResolvedValue(mockProject as any)

            const result = await verifyProjectOwnership('project-123', 'user-123')

            expect(result).toEqual(mockProject)
            expect(prisma.projects.findUnique).toHaveBeenCalledWith({
                where: { id: 'project-123' }
            })
        })

        it('should throw error when project not found', async () => {
            vi.mocked(prisma.projects.findUnique).mockResolvedValue(null)

            await expect(verifyProjectOwnership('project-123', 'user-123')).rejects.toThrow('Project not found')
        })

        it('should throw error when user is not owner', async () => {
            const mockProject = {
                id: 'project-123',
                user_id: 'other-user',
                name: 'Test Project'
            }
            vi.mocked(prisma.projects.findUnique).mockResolvedValue(mockProject as any)

            await expect(verifyProjectOwnership('project-123', 'user-123')).rejects.toThrow('Forbidden')
        })
    })

    describe('verifyCardOwnership', () => {
        it('should return card when user owns the parent project', async () => {
            const mockCard = {
                id: 'card-123',
                workspace_id: 'workspace-123',
                label: 'Test Card',
                workspaces: {
                    id: 'workspace-123',
                    project_id: 'project-123',
                    projects: {
                        id: 'project-123',
                        user_id: 'user-123'
                    }
                }
            }
            vi.mocked(prisma.cards.findUnique).mockResolvedValue(mockCard as any)

            const result = await verifyCardOwnership('card-123', 'user-123')

            expect(result).toEqual(mockCard)
            expect(prisma.cards.findUnique).toHaveBeenCalledWith({
                where: { id: 'card-123' },
                include: {
                    workspaces: {
                        include: {
                            projects: true
                        }
                    }
                }
            })
        })

        it('should throw error when card not found', async () => {
            vi.mocked(prisma.cards.findUnique).mockResolvedValue(null)

            await expect(verifyCardOwnership('card-123', 'user-123')).rejects.toThrow('Card not found')
        })

        it('should throw error when user does not own parent project', async () => {
            const mockCard = {
                id: 'card-123',
                workspaces: {
                    projects: {
                        user_id: 'other-user'
                    }
                }
            }
            vi.mocked(prisma.cards.findUnique).mockResolvedValue(mockCard as any)

            await expect(verifyCardOwnership('card-123', 'user-123')).rejects.toThrow('Forbidden')
        })
    })

    describe('verifyWorkspaceOwnership', () => {
        it('should return workspace when user owns the parent project', async () => {
            const mockWorkspace = {
                id: 'workspace-123',
                project_id: 'project-123',
                projects: {
                    id: 'project-123',
                    user_id: 'user-123'
                }
            }
            vi.mocked(prisma.workspaces.findUnique).mockResolvedValue(mockWorkspace as any)

            const result = await verifyWorkspaceOwnership('workspace-123', 'user-123')

            expect(result).toEqual(mockWorkspace)
        })

        it('should throw error when workspace not found', async () => {
            vi.mocked(prisma.workspaces.findUnique).mockResolvedValue(null)

            await expect(verifyWorkspaceOwnership('workspace-123', 'user-123')).rejects.toThrow('Workspace not found')
        })
    })

    describe('handleAuthError', () => {
        it('should return 401 for Unauthorized error', () => {
            const error = new Error('Unauthorized')
            const response = handleAuthError(error)

            expect(response.status).toBe(401)
        })

        it('should return 403 for Forbidden error', () => {
            const error = new Error('Forbidden')
            const response = handleAuthError(error)

            expect(response.status).toBe(403)
        })

        it('should return 404 for not found errors', () => {
            const error = new Error('Project not found')
            const response = handleAuthError(error)

            expect(response.status).toBe(404)
        })

        it('should return 500 for other errors', () => {
            const error = new Error('Something went wrong')
            const response = handleAuthError(error)

            expect(response.status).toBe(500)
        })

        it('should return 500 for non-Error objects', () => {
            const response = handleAuthError('string error')

            expect(response.status).toBe(500)
        })
    })
})

